#!/usr/bin/env node
/**
 * Write every font family name to font-names.txt (and font-names.html), one per
 * line, A-Z.
 *
 * A plain mirror of the shipped catalog, for cross-referencing. The .txt is for
 * grep/diff; the .html is for eyeballing in a browser (open it, Cmd-F to search).
 * Pulls names straight from the same three sources fontCatalog.ts merges:
 *
 *   src/lib/fonts.ts                 Bunny + Fontsource (auto-generated by popularity)
 *   src/lib/localFonts.generated.ts  self-hosted fonts from the `local:` YAML
 *   src/lib/localFonts.ts            manual self-hosted entries
 *
 * Names are deduped (a self-hosted family overriding a catalog one is listed
 * once) and sorted case-insensitively with natural number order, so e.g.
 * "Redaction 20" comes before "Redaction 100".
 *
 * Run:  npm run fonts:names   (also runs as part of  npm run fonts:all)
 */
const fs = require('fs');
const path = require('path');

const ROOT = path.join(__dirname, '..');
const SOURCES = [
  'src/lib/fonts.ts',
  'src/lib/localFonts.generated.ts',
  'src/lib/localFonts.ts'
];
const OUTPUT = 'font-names.txt';
// HTML mirror lives in static/ so the app serves it (linked from /about, opens
// in a new tab) and it's still a real file you can double-click locally.
const OUTPUT_HTML = 'static/font-names.html';

// Match a `family` property's string value. Handles both styles the two
// generators emit: unquoted keys in fonts.ts (`family: "Roboto"`) and quoted
// keys in localFonts.generated.ts (`"family": "Space Grotesk"`). Allows either
// quote char for the value, tolerating the other quote inside the name (e.g. an
// apostrophe). `\bfamily\b` skips `subfamily`; the value must be quoted, so the
// interface field `family: string;` never matches.
const FAMILY_RE = /["']?\bfamily\b["']?\s*:\s*(["'])(.*?)\1/g;

const names = new Set();
for (const rel of SOURCES) {
  const abs = path.join(ROOT, rel);
  const src = fs.readFileSync(abs, 'utf8');
  for (const m of src.matchAll(FAMILY_RE)) names.add(m[2]);
}

const sorted = [...names].sort((a, b) =>
  a.localeCompare(b, 'en', { sensitivity: 'base', numeric: true })
);

// Start with a notice that the file is generated. Both lines begin with `#`,
// so you can filter them out when cross-referencing: grep -v '^#'
const header =
  '# AUTO-GENERATED by scripts/list-font-names.cjs - do not edit by hand.\n' +
  '# Run: npm run fonts:names (or npm run fonts:all). A-Z.\n';

// Trailing newline so the file is POSIX-clean and diffs stay tidy.
fs.writeFileSync(path.join(ROOT, OUTPUT), header + sorted.join('\n') + '\n');
console.log(`Wrote ${sorted.length} font names to ${OUTPUT}`);

// Browser mirror: open font-names.html, Cmd-F to find a name. Just the names,
// nothing else on the page (no heading, no instructions).
const esc = (s) =>
  s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const htmlList = sorted.map((n) => `      <li>${esc(n)}</li>`).join('\n');
const html = `<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>TypefaceOff fonts</title>
    <style>
      :root { color-scheme: light dark; }
      body { font: 15px/1.55 ui-monospace, SFMono-Regular, Menlo, Consolas, monospace; max-width: 42rem; margin: 2rem auto; padding: 0 1rem; }
      ul { list-style: none; padding: 0; margin: 0; }
      li { padding: 1px 0.4rem; border-radius: 3px; }
      li:nth-child(even) { background: color-mix(in srgb, currentColor 7%, transparent); }
    </style>
  </head>
  <body>
    <ul>
${htmlList}
    </ul>
  </body>
</html>
`;
fs.writeFileSync(path.join(ROOT, OUTPUT_HTML), html);
console.log(`Wrote ${sorted.length} font names to ${OUTPUT_HTML}`);
